import React, { useEffect, useState } from 'react';
import axios from 'axios';
import { useCursor, useScrollReveal } from './hooks/useAnimations';
import Navbar from './components/Navbar';
import Hero from './components/Hero';
import About from './components/About';
import Skills from './components/Skills';
import Projects from './components/Projects';
import Experience from './components/Education';
import Contact from './components/Contact';
import Footer from './components/Footer';
import './index.css';

const Loader = () => (
  <div style={{
    position: 'fixed', inset: 0, background: 'var(--bg)',
    display: 'flex', flexDirection: 'column', alignItems: 'center', justifyContent: 'center',
    zIndex: 9999,
  }}>
    <div style={{
      fontFamily: 'Syne', fontSize: 52, fontWeight: 800,
      background: 'linear-gradient(135deg, var(--violet), var(--cyan))',
      WebkitBackgroundClip: 'text', WebkitTextFillColor: 'transparent',
      animation: 'pulse 1.2s ease-in-out infinite',
      marginBottom: 16,
    }}>AG</div>
    <div style={{ display: 'flex', gap: 6 }}>
      {[0,1,2].map(i => (
        <div key={i} style={{
          width: 8, height: 8, borderRadius: '50%',
          background: 'var(--violet)',
          animation: `bounce 0.8s ease ${i * 0.15}s infinite alternate`,
        }} />
      ))}
    </div>
    <style>{`
      @keyframes bounce { to { transform: translateY(-12px); opacity: .4; } }
      @keyframes pulse { 0%,100%{opacity:1} 50%{opacity:.5} }
    `}</style>
  </div>
);

function App() {
  const [data, setData] = useState(null);
  const [loading, setLoading] = useState(true);

  useCursor();
  useScrollReveal();

  useEffect(() => {
    // Scroll reveal CSS
    const style = document.createElement('style');
    style.textContent = `
      .reveal { opacity: 0; transform: translateY(28px); transition: opacity 0.7s ease, transform 0.7s ease; }
      .reveal.anim-fade-left { transform: translateX(-28px); }
      .reveal.anim-fade-right { transform: translateX(28px); }
      .reveal.revealed { opacity: 1 !important; transform: none !important; }
    `;
    document.head.appendChild(style);

    // Fetch portfolio data from backend
    axios.get('/api/portfolio')
      .then(res => setData(res.data))
      .catch(() => {
        // Fallback data if backend not running
        setData({
          personal: {
            name: 'Anushka Garg', role: 'Full Stack Developer',
            tagline: 'I build things for the web — from pixel to server.',
            about: "Hi! I'm Anushka Garg, a passionate Full Stack Developer who bridges elegant frontends with robust backends.",
            email: 'anushkagarg@gmail.com',
            github: 'https://github.com/anushkagarg',
            linkedin: 'https://linkedin.com/in/anushkagarg',
            location: 'India', available: true,
          },
          skills: [
            { name:'React.js', level:90, category:'Frontend', icon:'⚛️' },
            { name:'JavaScript', level:92, category:'Frontend', icon:'🟨' },
            { name:'HTML & CSS', level:95, category:'Frontend', icon:'🎨' },
            { name:'Node.js', level:85, category:'Backend', icon:'🟢' },
            { name:'PHP', level:75, category:'Backend', icon:'🐘' },
            { name:'MongoDB', level:80, category:'Database', icon:'🍃' },
            { name:'SQL', level:78, category:'Database', icon:'🗄️' },
            { name:'REST APIs', level:88, category:'Backend', icon:'🔌' },
          ],
          projects: [
            { id:1, title:'Aarogya — AI Symptom Checker', description:'Rural health app with Claude AI integration.', tech:['React','Node.js','AI'], github:'#', live:'#', color:'#10b981', icon:'🩺', featured:true },
            { id:2, title:'E-Commerce Platform', description:'Full stack shopping platform with payments.', tech:['React','Node.js','MongoDB'], github:'#', live:'#', color:'#f59e0b', icon:'🛍️', featured:true },
            { id:3, title:'Task Management App', description:'Kanban board with drag-and-drop.', tech:['React','Node.js'], github:'#', live:'#', color:'#8b5cf6', icon:'📋', featured:false },
            { id:4, title:'Student Result Portal', description:'PHP + SQL marks management system.', tech:['PHP','SQL','HTML'], github:'#', live:'#', color:'#ef4444', icon:'🎓', featured:false },
          ],
          experience: [
            { year:'2024–Present', role:'Full Stack Developer', company:'Freelance', desc:'Building custom web applications for clients.' },
            { year:'2023–2024', role:'Frontend Developer Intern', company:'TechStartup Pvt. Ltd.', desc:'Built React components, improved performance by 40%.' },
            { year:'2022–2023', role:'Web Development Trainee', company:'Coding Institute', desc:'Learned full stack development from scratch.' },
          ],
          stats: [
            { label:'Projects Built', value:'20+' },
            { label:'Technologies', value:'8+' },
            { label:'GitHub Commits', value:'500+' },
            { label:'Happy Clients', value:'10+' },
          ],
        });
      })
      .finally(() => setTimeout(() => setLoading(false), 1200));
  }, []);

  if (loading) return <Loader />;

  return (
    <>
      {/* Custom cursor */}
      <div className="cursor-dot" />
      <div className="cursor-ring" />

      <Navbar name={data.personal.name} />
      <Hero data={{ ...data.personal, stats: data.stats }} />
      <About data={data.personal} />
      <Skills data={data.skills} />
      <Projects data={data.projects} />
      <Experience data={data.experience} />
      <Contact data={data.personal} />
      <Footer name={data.personal.name} />
    </>
  );
}

export default App;
